import os
import sys
import json
import argparse
import torch
from pathlib import Path
from typing import Dict, Any, List
import numpy as np
from PIL import Image
import copy
import traceback
import inspect
from lerobot.policies.pi0 import PI0Policy
from lerobot.policies.factory import make_pre_post_processors
from VLABench.evaluation.evaluator.base import Evaluator
from transformers import AutoTokenizer

os.environ['HF_HUB_OFFLINE'] = '1'

class RecordingEvaluator(Evaluator):
    def __init__(self, tasks: List[str], n_episodes: int, episode_config=None, max_steps_per_episode: int = 500, **kwargs):
        if isinstance(episode_config, (str, Path)):
            episode_config_path = Path(episode_config)
            if episode_config_path.exists():
                with open(episode_config_path, 'r') as f:
                    episode_config = json.load(f)
            else:
                episode_config = None
        super().__init__(
            tasks=tasks,
            n_episodes=n_episodes,
            episode_config=episode_config,
            max_substeps=1,
            tolerance=0.01,
            metrics=["success_rate"],
            visulization=False,
            eval_unseen=False,
            unnorm_key="primitive",
            **kwargs
        )
        self.episode_results: List[Dict] = []
        self.max_steps_per_episode = max_steps_per_episode
        print(f'RecordingEvaluator initialized with tasks={tasks}, n_episodes={n_episodes}, max_steps={max_steps_per_episode}')

    def evaluate_single_episode(self, agent, task: str, episode_index: int, episode_cfg: Dict, **kwargs):
        try:
            info = super().evaluate_single_episode(
                agent, task, episode_index, episode_cfg,
                max_episode_length=self.max_steps_per_episode, **kwargs
            )
            success = bool(info.get('success', False) if isinstance(info, dict) else False)
        except Exception as e:
            print(f'Error in episode {task} #{episode_index}: {str(e)}')
            traceback.print_exc()
            success = False
            info = {'success': False}
        self.episode_results.append({
            'task': task,
            'episode_index': episode_index,
            'success': success
        })
        return info

    def evaluate(self, agent):
        print('Starting full evaluation with RecordingEvaluator...')
        metrics = super().evaluate(agent)
        print('Evaluation completed. Metrics:', metrics)
        return metrics

class PI0Agent:
    def __init__(self, checkpoint_path: str = None):
        self.name = 'pi0_base_adapter'
        self.control_mode = 'ee'
        self.device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')
        print(f'Loading PI0 on {self.device}')
        self.policy = PI0Policy.from_pretrained('lerobot/pi0_base').to(self.device)
        self.policy.eval()
        self.preprocess, self.postprocess = make_pre_post_processors(
            self.policy.config,
            'lerobot/pi0_base',
            preprocessor_overrides={'device_processor': {'device': str(self.device)}}
        )
        self.tokenizer = AutoTokenizer.from_pretrained('google/paligemma-3b-pt-224')
        if hasattr(self.preprocess, 'processors'):
            self.processors = self.preprocess.processors
        elif hasattr(self.preprocess, 'steps'):
            self.processors = self.preprocess.steps
        else:
            self.processors = []
        print('Number of processors:', len(self.processors))
        for i, p in enumerate(self.processors):
            print(f'  {i}: {type(p).__name__}')
        self.reset()
        self.error_printed = False
        print('PI0Agent initialized successfully')

    def reset(self):
        self.pending_actions = None
        self.action_chunk_idx = 0
        self.current_instruction = None

    def _to_device(self, batch: Any, device: torch.device):
        if isinstance(batch, dict):
            return {k: self._to_device(v, device) for k, v in batch.items()}
        elif isinstance(batch, torch.Tensor):
            return batch.to(device)
        elif isinstance(batch, list):
            return [self._to_device(x, device) for x in batch]
        elif isinstance(batch, tuple):
            return tuple(self._to_device(x, device) for x in batch)
        return batch

    def _action_to_ee(self, action, current_ee_state):
        if torch.is_tensor(action):
            action = action.cpu().numpy()
        action = np.asarray(action).flatten()[:7].astype(np.float32)
        current_ee = np.asarray(current_ee_state).flatten().astype(np.float32)
        current_pos = current_ee[:3]
        current_euler = current_ee[3:6] if len(current_ee) >= 6 else np.zeros(3, dtype=np.float32)
        pos = current_pos + action[:3] * 0.05
        euler = current_euler + action[3:6] * 0.25
        grip_val = 1.0 if action[6] > 0.5 else -1.0
        grip = np.array([grip_val, grip_val], dtype=np.float32)
        return (pos, euler, grip)

    def _prepare_observation(self, obs_dict, instruction):
        rgb = obs_dict.get('rgb')
        if rgb is None:
            rgb = np.zeros((4, 224, 224, 3), dtype=np.uint8)
        if isinstance(rgb, torch.Tensor):
            rgb = rgb.cpu().numpy()
        if rgb.ndim == 3:
            rgb = rgb[None, ...]
        if rgb.shape[1:] == (480, 480, 3) or rgb.shape[1:] == (3, 480, 480):
            rgb = np.transpose(rgb, (0, 2, 3, 1)) if rgb.shape[1] == 3 else rgb
            from PIL import Image
            rgb_pil = []
            for i in range(min(4, rgb.shape[0])):
                img = rgb[i]
                if img.dtype != np.uint8:
                    img = (img * 255).clip(0, 255).astype(np.uint8)
                pil_img = Image.fromarray(img).resize((224, 224), Image.BILINEAR)
                rgb_pil.append(pil_img)
            rgb = rgb_pil
        else:
            from PIL import Image
            rgb_pil = []
            for i in range(min(4, len(rgb) if isinstance(rgb, list) else rgb.shape[0])):
                img = rgb[i]
                if isinstance(img, np.ndarray):
                    if img.dtype != np.uint8:
                        img = (img * 255).clip(0, 255).astype(np.uint8)
                    pil_img = Image.fromarray(img).resize((224, 224), Image.BILINEAR)
                else:
                    pil_img = img.resize((224, 224), Image.BILINEAR) if hasattr(img, 'resize') else Image.new('RGB', (224, 224))
                rgb_pil.append(pil_img)
            rgb = rgb_pil
        images = {
            'base_0_rgb': rgb[0],
            'left_wrist_0_rgb': rgb[2] if len(rgb) > 2 else rgb[0],
            'right_wrist_0_rgb': rgb[3] if len(rgb) > 3 else rgb[1] if len(rgb) > 1 else rgb[0],
        }
        state = obs_dict.get('ee_state', obs_dict.get('state', np.zeros(8, dtype=np.float32)))
        if isinstance(state, torch.Tensor):
            state = state.cpu().numpy()
        state = np.asarray(state).flatten()[:8].astype(np.float32)
        state = np.pad(state, (0, 32 - 8), mode='constant').astype(np.float32)
        dummy_action = np.zeros((32,), dtype=np.float32)
        batch = {
            'observation': {
                'images': images,
                'state': state,
            },
            'action': dummy_action,
            'complementary_data': {'task': instruction},
            'task': instruction,
        }
        return batch

    def _safe_preprocess(self, batch):
        try:
            if not isinstance(batch, dict) or 'observation' not in batch:
                print('Invalid batch for preprocess, using fallback structure')
                return batch
            processed = copy.deepcopy(batch)
            for i, processor in enumerate(self.processors):
                proc_name = type(processor).__name__
                try:
                    if 'Language' in proc_name or 'Tokenizer' in proc_name or 'NewLine' in proc_name or 'Pi0NewLine' in proc_name:
                        if 'task' in processed or ('complementary_data' in processed and 'task' in processed.get('complementary_data', {})):
                            task_str = processed.get('task') or processed.get('complementary_data', {}).get('task', '')
                            if isinstance(task_str, str) and self.tokenizer is not None:
                                tokens = self.tokenizer(task_str, padding='max_length', truncation=True, max_length=128, return_tensors='pt')
                                if 'observation' not in processed:
                                    processed['observation'] = {}
                                processed['observation']['language'] = {
                                    'tokens': tokens['input_ids'].squeeze(0),
                                    'attention_mask': tokens['attention_mask'].squeeze(0),
                                }
                                if 'complementary_data' not in processed:
                                    processed['complementary_data'] = {}
                                processed['complementary_data']['language'] = task_str
                    processed = processor(processed)
                    if isinstance(processed, dict) and 'observation' not in processed and 'observation' in batch:
                        processed['observation'] = batch['observation']
                    if isinstance(processed, tuple) and len(processed) > 0:
                        processed = processed[0]
                except Exception as proc_e:
                    if not self.error_printed and i > 0:
                        print(f'Processor {i} ({proc_name}) had issue: {proc_e}')
                    if 'observation' not in processed and 'observation' in batch:
                        processed['observation'] = copy.deepcopy(batch['observation'])
                    continue
            if isinstance(processed, dict) and 'observation' in processed and 'images' in processed['observation']:
                print('FULL SEQUENTIAL PREPROCESS SUCCEEDED')
                self.error_printed = False
                return processed
            else:
                print('Preprocess did not produce observation.images, using fallback')
                return batch
        except Exception as e:
            if not self.error_printed:
                print(f'Preprocess error: {e}')
                self.error_printed = True
            return batch

    def predict(self, observation, **kwargs):
        try:
            instruction = observation.get('instruction', self.current_instruction or 'pick and place the object')
            self.current_instruction = instruction
            if self.pending_actions is not None and self.action_chunk_idx < len(self.pending_actions):
                action = self.pending_actions[self.action_chunk_idx]
                self.action_chunk_idx += 1
                current_ee = observation.get('ee_state', np.zeros(8))
                return self._action_to_ee(action, current_ee)
            batch = self._prepare_observation(observation, instruction)
            processed_batch = self._safe_preprocess(batch)
            processed_batch = self._to_device(processed_batch, self.device)
            with torch.no_grad():
                action_chunk = self.policy.predict_action_chunk(processed_batch)
            if isinstance(action_chunk, torch.Tensor):
                action_chunk = action_chunk.cpu().numpy()
            self.pending_actions = action_chunk[0] if action_chunk.ndim > 2 else action_chunk
            self.action_chunk_idx = 1
            current_ee = observation.get('ee_state', np.zeros(8))
            action = self.pending_actions[0]
            return self._action_to_ee(action, current_ee)
        except Exception as e:
            if not self.error_printed:
                print(f'Predict error (using fallback): {type(e).__name__}: {e}')
                traceback.print_exc()
                self.error_printed = True
            current_ee = observation.get('ee_state', np.zeros(8))
            if isinstance(current_ee, torch.Tensor):
                current_ee = current_ee.cpu().numpy()
            pos = current_ee[:3] + np.random.normal(0, 0.02, 3).astype(np.float32)
            euler = current_ee[3:6] + np.random.normal(0, 0.1, 3).astype(np.float32) if len(current_ee) > 3 else np.random.normal(0, 0.1, 3).astype(np.float32)
            grip = np.array([0.0, 0.0], dtype=np.float32)
            return (pos, euler, grip)

def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', type=str, required=True)
    parser.add_argument('--checkpoint', type=str, default='checkpoints/base')
    parser.add_argument('--output', type=str, required=True)
    args = parser.parse_args()
    data_path = Path(args.data_path)
    eval_config_path = data_path / 'eval_config.json'
    with open(eval_config_path, 'r') as f:
        eval_config = json.load(f)
    tasks = eval_config.get('benchmark_tasks', ['add_condiment', 'select_fruit', 'select_book'])
    n_episodes = eval_config.get('episodes_per_task', 20)
    max_steps = eval_config.get('max_steps_per_episode', 500)
    track_path = eval_config.get('eval_track_path', str(data_path / 'track_1_in_distribution.json'))
    print(f'Running evaluation on tasks: {tasks}, episodes_per_task={n_episodes}, track={track_path}')
    evaluator = RecordingEvaluator(
        tasks=tasks,
        n_episodes=n_episodes,
        episode_config=track_path,
        max_steps_per_episode=max_steps
    )
    agent = PI0Agent(checkpoint_path=args.checkpoint)
    metrics = evaluator.evaluate(agent)
    output = {
        'episodes': evaluator.episode_results,
        'total_episodes': len(evaluator.episode_results)
    }
    with open(args.output, 'w') as f:
        json.dump(output, f, indent=2)
    print('Final Result:', json.dumps(output))
    print('Test completed - check for shape/bridge/preprocess errors above. If no traceback and FULL SEQUENTIAL PREPROCESS SUCCEEDED in diagnostic, pipeline is fixed.')

if __name__ == '__main__':
    main()
